var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"으음…","JPN":"んん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하아, 이제야 일어났네.","JPN":"はあ、やっと起きたのね。","ENG":"*Sigh* You're finally awake.","TWN":"哼，你現在才睡醒是吧。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"낭자…? 왜 그대가 내 앞자리에 있는 거요?","JPN":"貴殿……？　何ゆえ自分の前の席に……？","ENG":"You're, blonde maiden...? Why are you sitting in front of me?","TWN":"姑娘…？你為何要站在在下前面？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"\xA0그야 마지막 수업은 한참 전에 끝났으니까.","JPN":"\xA0今日の授業はもうとっくに終わったからよ。","ENG":"\xA0Because our last class ended ages ago.","TWN":"因為最後一堂課早就下課了，"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 오늘 교실 문단속은 나라구.","JPN":"そして、今日の教室の戸締り当番は私。","ENG":"Also, I'm supposed to lock up our classroom today.","TWN":"然後我今天是值日生負責鎖門。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"폐를 끼쳤구려.","JPN":"それは……ご迷惑をお掛けしました。","ENG":"I have caused you inconvenience.","TWN":"給你添麻煩了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼, 수업이 끝난 뒤에도 본인을 빤히 지켜 보기만 하던 거요?","JPN":"にしても、授業が終わってからずっと自分をじろじろと見ていたんですか？","ENG":"Then, have you been staring at me this whole time after class had ended?","TWN":"所以下課後你就一直凝視在下嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"누, 누가 빤히 지켜봤다는 거야?! 다른 사람이 들으면 오해할 소리 좀 하지 마!","JPN":"じ、じろじろって何！？　変な言い方はやめて！","ENG":"W-who said anything about staring?! Stop saying things that could give people the wrong idea!","TWN":"誰，誰凝視你啦？！少說這種別人聽到會誤會的話！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"깨웠는데 네가 안 일어난 거거든?!","JPN":"起こしても起きなかったのはあんたでしょう！？","ENG":"I tried to wake you up, but you wouldn't budge!","TWN":"我有叫你，是你沒起來好嗎！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그리고 난 너 안 보고 폰으로 게임 하고 있었거든?! 신기록 경신이었거든?!","JPN":"それに、私はスマホゲームに熱中していたの！　新記録達成よ？","ENG":"Also, I wasn't just waiting on you! I was playing games on my phone! See? I even broke my previous high score!","TWN":"而且我才沒有在看你，我是在玩手遊，而且還創新紀錄咧！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…너 말이야. 진짜로 무슨 병이라도 있는 건 아니지?","JPN":"……あんたってさ。それ、なにかの病気じゃない？","ENG":"...I'm just asking, but... you're not sick, are you?","TWN":"…我問你，你該不會身體真的有什麼問題吧？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"낮에만 그렇게 자는 건 누가 봐도 이상하다고.","JPN":"昼の間、ぶっ通しで寝るなんて明らかにおかしいわよ。","ENG":"Because it's weird to see someone sleep all day like that.","TWN":"只有白天才睡得那麼熟，一定哪裡有問題吧？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아마도 습관이 되었기 때문일 거요. 고향에서는 주로 밤에만 활동했으니.","JPN":"おそらく昔からの習慣のせいでしょう。故郷では夜が主な活動時間だったので。","ENG":"Most likely, it is out of habit. In my hometown, I primarily worked during the night.","TWN":"應該是習慣的關係，因為在老家時，主要的活動時間都是在晚上。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"하아? 대체 뭣 때문에 밤에 깨어 있는 건데?","JPN":"はあ？　どうして夜？","ENG":"Huh? What were you doing staying up all night?","TWN":"蛤？為什麼專挑晚上？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"악인들의 암약과 음모는 주로 밤에 일어나는 법이니, 본인 또한 그런 자들을 처단하기 위해…","JPN":"悪人たちは夜に暗躍し、黒い計画は夜実行されるもの、自分はそのようなものを始末するため……","ENG":"Malicious schemes and conspiracies are bound to happen at night. I was there to put an end to those people...","TWN":"因為壞人通常都在晚上犯罪，所以也只能在晚上處決他們…"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"처단…?","JPN":"始末……？","ENG":"Put an end...?","TWN":"處決…？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};